const repo = "Martinmjal/sales_ai_agent_case_study";
const parent = "https://github.com/Martinmjal/sales_ai_agent_case_study/issues/1";
const created = [];

async function create(title, what, criteria, blockerIssues) {
  const blocked = blockerIssues.length
    ? blockerIssues.map(i => `- #${i.issue_number} — ${i.title}`).join("\n")
    : "- None — can start immediately.";
  const body = `## Parent

${parent}

## What to build

${what}

## Acceptance criteria

${criteria.map(c => `- [ ] ${c}`).join("\n")}

## Blocked by

${blocked}
`;
  const result = await tools.mcp__codex_apps__github_create_issue({
    repository_full_name: repo,
    title,
    body,
    labels: ["ready-for-agent"]
  });
  const issue = result?.structuredContent?.issue;
  if (!issue?.issue_number) {
    text(JSON.stringify(result));
    throw new Error(`Issue creation failed for ${title}`);
  }
  const item = {
    issue_number: issue.issue_number,
    title: issue.title,
    url: issue.url || issue.display_url
  };
  created.push(item);
  return item;
}

